VkPhysicalDevice physicalDevice = VK_NULL_HANDLE;
VkFormat format = VK_NULL_HANDLE;
VkImageType type = VK_NULL_HANDLE;
VkSampleCountFlagBits samples = VK_NULL_HANDLE;
VkImageUsageFlags usage = 0;
VkImageTiling tiling = VK_NULL_HANDLE;
uint32_t propertyCount = 0;
VkSparseImageFormatProperties properties = {};
properties.sType = VK_STRUCTURE_TYPE_SPARSE_IMAGE_FORMAT_PROPERTIES;

vkGetPhysicalDeviceSparseImageFormatProperties(
 physicalDevice,
 format,
 type,
 samples,
 usage,
 tiling,
 &propertyCount,
 &properties
);
